/**
 * gi-docgen navigation script.
 *
 * Reads the shallow NavigationElement[] from window.navigationData
 * (generated by GiDocgenTheme.getNavigation — flat list of modules,
 * scope wrapper already stripped) and builds the sidebar DOM as simple links.
 */

async function decompressJson(base64Data) {
	const binaryData = Uint8Array.from(atob(base64Data), (c) => c.charCodeAt(0));
	const blob = new Blob([binaryData]);
	const decompressedStream = blob.stream().pipeThrough(new DecompressionStream("deflate"));
	const decompressedText = await new Response(decompressedStream).text();
	return JSON.parse(decompressedText);
}

function getCurrentPath() {
	return window.location.pathname;
}

function isCurrentPage(path) {
	if (!path) return false;
	const base = document.documentElement.dataset.base ?? "./";
	const absPath = new URL(path, new URL(base, window.location.href)).pathname;
	return getCurrentPath() === absPath;
}

function resolveHref(path) {
	const base = document.documentElement.dataset.base ?? "./";
	return new URL(path, new URL(base, window.location.href)).href;
}

function renderModule(mod) {
	const li = document.createElement("li");
	if (mod.path) {
		const a = document.createElement("a");
		a.href = resolveHref(mod.path);
		a.textContent = mod.text;
		if (isCurrentPage(mod.path)) a.classList.add("current");
		li.appendChild(a);
	} else {
		const span = document.createElement("span");
		span.textContent = mod.text;
		li.appendChild(span);
	}
	return li;
}

/** Waits until window.navigationData is available (navigation.js may load async). */
function waitForNavigationData() {
	if (window.navigationData) return Promise.resolve();
	return new Promise((resolve) => {
		const script = document.getElementById("tsd-nav-script");
		if (script) {
			script.addEventListener("load", resolve, { once: true });
		} else {
			// Fallback: poll until available
			const interval = setInterval(() => {
				if (window.navigationData) {
					clearInterval(interval);
					resolve();
				}
			}, 50);
		}
	});
}

async function buildNav() {
	await waitForNavigationData();
	if (!window.navigationData) return;

	const container = document.getElementById("tsd-nav-container");
	if (!container) return;

	const nav = await decompressJson(window.navigationData);

	container.innerHTML = "";
	for (const mod of nav) {
		container.appendChild(renderModule(mod));
	}
}

buildNav();
